     9→ * Direct-API switching stays on /model — /agent 換人（CLI subprocess），
    10→ * /model 換腦（API endpoint）。
    11→ */
    12→import { Context } from "grammy";
    13→import { config } from "../config.js";
    14→import {
    15→  acpProvidersConfigPath,
    16→  loadAcpProviders,
    17→  DEFAULT_BACKEND_KEY,
    18→} from "../acp-providers.js";
    19→import { deps } from "./deps.js";
    20→
    21→export async function handleAgent(ctx: Context): Promise<void> {
    22→  const { isAllowed, sessions } = deps();
    23→  if (!isAllowed(ctx)) return;
    24→  const chatId = ctx.chat?.id;
    25→  const userId = ctx.from?.id;
    26→  if (!chatId) return;
    27→
    28→  const arg = (typeof ctx.match === "string" ? ctx.match : "").trim().toLowerCase();
    29→  const backends = loadAcpProviders();
    30→  const session = sessions.peek(chatId);
    31→  const isEnvFallbackOnly =
    32→    Object.keys(backends).length === 1 && backends[DEFAULT_BACKEND_KEY] !== undefined;
    33→
    34→  // No argument: show current backend + available list.
    35→  if (!arg) {
    36→    const current = describeCurrent(session?.activeProvider, session?.acpBackend);
    37→    const lines = [
    38→      `🤖 當前 agent：${current}`,
    39→      "",
    40→      "可用 agent：",
    41→      ...Object.values(backends).map((b) => {
    42→        const marker = session?.activeProvider === "acp" && session?.acpBackend === b.key ? " ← 當前" : "";
    43→        const pin = b.model ? `，pin ${b.model}${b.effort ? `/${b.effort}` : ""}` : "";
    44→        return `• \`${b.key}\` — ${b.label}（${b.command} ${b.args.join(" ")}${pin}）${marker}`;
    45→      }),
    46→      "",
    47→      "用法：`/agent <名稱>` 切換（自動交接對話摘要，不掉記憶）",
    48→      "切 Direct API 請用 /model。",
    49→    ];
    50→    if (isEnvFallbackOnly) {
    51→      lines.push(
    52→        "",
    53→        `⚠️ 尚未建立 backend 設定檔，目前只有 .env 預設 agent。`,
    54→        `建立 ${acpProvidersConfigPath()} 後即可多 agent 切換。`,
    55→      );
    56→    }
    57→    await ctx.reply(lines.join("\n"), { parse_mode: "Markdown" });
    58→    return;
    59→  }
    60→
    61→  const def = backends[arg];
    62→  if (!def) {
    63→    await ctx.reply(
    64→      `❌ 未知 agent "${arg}"。可用：${Object.keys(backends).map((k) => `\`${k}\``).join("、")}`,
    65→      { parse_mode: "Markdown" },
    66→    );
    67→    return;
    68→  }
    69→
    70→  if (session?.activeProvider === "acp" && session.acpBackend === arg) {
    71→    await ctx.reply(`已經在使用 ${def.label} 了。`);
    72→    return;
    73→  }
    74→
    75→  if (session?.inflight) {
    76→    await ctx.reply("⚠️ 目前有 turn 進行中，請等它完成或先 /cancel 再切換。");
    77→    return;
    78→  }
    79→
    80→  // exportSession runs the local-LLM handoff summary — takes a few seconds.
    81→  await ctx.reply(`🔄 正在交接對話脈絡並切換到 ${def.label}…`);
    82→  try {
    83→    await sessions.switchAgent(chatId, arg, userId);
    84→    await ctx.reply(
    85→      `✅ 已切換到 **${def.label}**（前段對話摘要已注入新 session）`,
    86→      { parse_mode: "Markdown" },
    87→    );
    88→  } catch (err) {
    89→    await ctx.reply(`❌ 切換失敗：${(err as Error).message}`);
    90→  }
    91→}
    92→
    93→function describeCurrent(activeProvider?: string, acpBackend?: string): string {
    94→  if (!activeProvider) return `(尚無 session — 下一則訊息會用 .env 預設 ${config.agent.command} 開啟)`;
    95→  if (activeProvider !== "acp") return `Direct API provider \`${activeProvider}\`（用 /model 管理）`;
    96→  if (acpBackend) {
    97→    const def = loadAcpProviders()[acpBackend];
    98→    return def ? `**${def.label}**（\`${acpBackend}\`）` : `\`${acpBackend}\`（設定檔已無此項）`;
    99→  }
   100→  return `.env 預設（${config.agent.command} ${config.agent.args.join(" ")}）`;
   101→}
   102→

