// Smoke test: verify provider module loads, AcpProvider implements Provider interface,
// and config.ts exposes the new multi-model fields without import errors.
//
// Usage: node scripts/check-provider.mjs
// Exit 0 = OK, 1 = failure

import { AcpProvider, DirectProvider, McpPool, runToolLoop, OpenAICompatAdapter, resolveBaseUrl } from "../dist/provider/index.js";
import { config } from "../dist/config.js";

let ok = true;
function assert(cond, msg) {
  if (!cond) { console.error(`❌ ${msg}`); ok = false; }
  else { console.log(`✅ ${msg}`); }
}

// 1. AcpProvider class exists and is constructable (won't actually spawn)
assert(typeof AcpProvider === "function", "AcpProvider is a constructor");
assert(AcpProvider.prototype.prompt, "AcpProvider has prompt()");
assert(AcpProvider.prototype.cancel, "AcpProvider has cancel()");
assert(AcpProvider.prototype.close, "AcpProvider has close()");

// 2. Config has new multi-model fields
assert(typeof config.defaultProvider === "string", `config.defaultProvider = "${config.defaultProvider}"`);
assert(typeof config.models === "object", "config.models is an object");
assert(typeof config.models.anthropic === "string", `config.models.anthropic = "${config.models.anthropic}"`);
assert(typeof config.models.local === "string", `config.models.local = "${config.models.local}"`);
assert(typeof config.apiKeys === "object", "config.apiKeys is an object");
assert(typeof config.ollamaUrl === "string", `config.ollamaUrl = "${config.ollamaUrl}"`);

// 3. DirectProvider
assert(typeof DirectProvider === "function", "DirectProvider is a constructor");
assert(DirectProvider.prototype.prompt, "DirectProvider has prompt()");
assert(DirectProvider.prototype.cancel, "DirectProvider has cancel()");
assert(DirectProvider.prototype.close, "DirectProvider has close()");

// 4. McpPool
assert(typeof McpPool === "function", "McpPool is a constructor");
const pool = new McpPool();
assert(pool.listTools().length === 0, "McpPool starts with 0 tools");
assert(pool.size === 0, "McpPool starts with 0 servers");

