/**
 * /agent command handler — hot-swap between ACP CLI backends
 * (Kiro / Claude Code / Codex) with conversation handoff.
 *
 * /agent          → show current backend + available list
 * /agent <name>   → archive current session → spawn target CLI → new session
 *                   with the handoff archive injected into its preamble
 *
 * Direct-API switching stays on /model — /agent 換人（CLI subprocess），
 * /model 換腦（API endpoint）。
 */
import { Context } from "grammy";
import { config } from "../config.js";
import {
  acpProvidersConfigPath,
  loadAcpProviders,
  seedAcpProvidersFile,
  DEFAULT_BACKEND_KEY,
} from "../acp-providers.js";
import { deps } from "./deps.js";

export async function handleAgent(ctx: Context): Promise<void> {
  const { isAllowed, sessions } = deps();
  if (!isAllowed(ctx)) return;
  const chatId = ctx.chat?.id;
  const userId = ctx.from?.id;
  if (!chatId) return;

  const arg = (typeof ctx.match === "string" ? ctx.match : "").trim().toLowerCase();
  const backends = loadAcpProviders();
  const session = sessions.peek(chatId);
  const isEnvFallbackOnly =
    Object.keys(backends).length === 1 && backends[DEFAULT_BACKEND_KEY] !== undefined;

  // No argument: show current backend + available list.
  if (!arg) {
    const current = describeCurrent(session?.activeProvider, session?.acpBackend);
    const lines = [
      `🤖 當前 agent：${current}`,
      "",
      "可用 agent：",
      ...Object.values(backends).map((b) => {
        const marker = session?.activeProvider === "acp" && session?.acpBackend === b.key ? " ← 當前" : "";
        const pin = b.model ? `，pin ${b.model}${b.effort ? `/${b.effort}` : ""}` : "";
        return `• \`${b.key}\` — ${b.label}（${b.command} ${b.args.join(" ")}${pin}）${marker}`;
      }),
      "",
      "用法：`/agent <名稱>` 切換（自動交接對話摘要，不掉記憶）",
      "切 Direct API 請用 /model。",
    ];
    if (isEnvFallbackOnly) {
      lines.push(
        "",
        `⚠️ 尚未建立 backend 設定檔，目前只有 .env 預設 agent。`,
        `建立 ${acpProvidersConfigPath()} 後即可多 agent 切換。`,
      );
    }
    await ctx.reply(lines.join("\n"), { parse_mode: "Markdown" });
    return;
  }

  const def = backends[arg];
  if (!def) {
    await ctx.reply(
      `❌ 未知 agent "${arg}"。可用：${Object.keys(backends).map((k) => `\`${k}\``).join("、")}`,
      { parse_mode: "Markdown" },
    );
    return;
  }

  if (session?.activeProvider === "acp" && session.acpBackend === arg) {
    await ctx.reply(`已經在使用 ${def.label} 了。`);
    return;
  }

  if (session?.inflight) {
    await ctx.reply("⚠️ 目前有 turn 進行中，請等它完成或先 /cancel 再切換。");
    return;
  }

  // exportSession runs the local-LLM handoff summary — takes a few seconds.
  await ctx.reply(`🔄 正在交接對話脈絡並切換到 ${def.label}…`);
  try {
    await sessions.switchAgent(chatId, arg, userId);
    await ctx.reply(
      `✅ 已切換到 **${def.label}**（前段對話摘要已注入新 session）`,
      { parse_mode: "Markdown" },
    );
  } catch (err) {
    await ctx.reply(`❌ 切換失敗：${(err as Error).message}`);
  }
}

function describeCurrent(activeProvider?: string, acpBackend?: string): string {
  if (!activeProvider) return `(尚無 session — 下一則訊息會用 .env 預設 ${config.agent.command} 開啟)`;
  if (activeProvider !== "acp") return `Direct API provider \`${activeProvider}\`（用 /model 管理）`;
  if (acpBackend) {
    const def = loadAcpProviders()[acpBackend];
    return def ? `**${def.label}**（\`${acpBackend}\`）` : `\`${acpBackend}\`（設定檔已無此項）`;
  }
  return `.env 預設（${config.agent.command} ${config.agent.args.join(" ")}）`;
}

