// Smoke test: /agent init seed 範本（buildSeedTemplate 純邏輯 + parseAcpProviders 往返
// + seedAcpProvidersFile 不覆蓋既有檔）。
//
// Usage: node scripts/check-agent-init.mjs
// Exit 0 = OK, 1 = failure

import { existsSync, readFileSync } from "node:fs";
import {
  buildSeedTemplate,
  parseAcpProviders,
  seedAcpProvidersFile,
  acpProvidersConfigPath,
} from "../dist/acp-providers.js";

let ok = true;
function assert(cond, msg) {
  if (!cond) { console.error(`❌ ${msg}`); ok = false; }
  else { console.log(`✅ ${msg}`); }
}

// 1. .env agent 是 kiro → kiro entry 用真實 command，其餘為 scaffold
const t1 = buildSeedTemplate("kiro-cli", ["acp", "--agent", "main"], "claude-opus-4.6");
assert(Object.keys(t1).length === 3, "kiro env → 3 entries（kiro/claude/codex）");
assert(t1.kiro?.command === "kiro-cli acp --agent main", `kiro entry 保留 .env 完整 command（${t1.kiro?.command}）`);
assert(t1.kiro?.model === "claude-opus-4.6", "kiro entry 帶入 model pin");
assert(t1.kiro?.label.includes(".env"), "kiro label 標示 .env 當前 agent");
assert(t1.claude?.label.includes("請確認"), "claude scaffold label 提示請確認 command");
assert(t1.codex?.label.includes("請確認"), "codex scaffold label 提示請確認 command");

// 2. .env agent 是 claude-agent-acp（npx 形式）→ claude entry 為 env entry
const t2 = buildSeedTemplate("npx", ["claude-agent-acp"], "claude-fable-5", "medium");
assert(t2.claude?.command === "npx claude-agent-acp", "npx claude-agent-acp 判為 claude key");
assert(t2.claude?.effort === "medium", "claude entry 帶入 effort pin");
assert(t2.claude?.label.includes(".env"), "claude label 標示 .env 當前 agent");
assert(t2.kiro?.command === "kiro-cli acp", "kiro scaffold 用常見 command");

// 3. 未知 command → default key + 3 scaffolds
const t3 = buildSeedTemplate("some-agent", []);
assert(Object.keys(t3).length === 4, "未知 env agent → default + 3 scaffolds = 4 entries");
assert(t3.default?.command === "some-agent", "未知 env agent 落在 default key");

// 4. 序列化不殘留 undefined 欄位，且能被 parseAcpProviders 往返
const raw = JSON.stringify(t1, null, 2);
assert(!raw.includes("undefined"), "序列化無 undefined 殘留");
const parsed = parseAcpProviders(raw, "main");
assert(Object.keys(parsed).length === 3, "往返 parseAcpProviders 得 3 backends");
assert(
  parsed.kiro.args.filter((a) => a === "--agent").length === 1,
  "kiro --agent 不因 agentName 重複附加",
);
assert(parsed.claude.command === "npx", "claude backend command token 正確拆分");

// 5. seedAcpProvidersFile 不覆蓋既有檔（僅在本機已有設定檔時驗證，避免副作用）
const cfgPath = acpProvidersConfigPath();
if (existsSync(cfgPath)) {
  const before = readFileSync(cfgPath, "utf8");
  const result = seedAcpProvidersFile();
  const after = readFileSync(cfgPath, "utf8");
  assert(result.created === false, "既有設定檔 → created:false");
  assert(before === after, "既有設定檔內容未被改動");
} else {
  console.log("⏭️ 本機無設定檔，跳過不覆蓋驗證（避免寫入真實 MEMORY_DIR）");
}

process.exit(ok ? 0 : 1);

